    if (_usernameController.text.isEmpty || _passwordController.text.isEmpty) {
      setState(() {
        _message = 'Please fill in all fields';
      });
      return;
    }

    setState(() {
      _isLoading = true;
      _message = '';
    });

    final result = await _apiClient.login(
      _usernameController.text,
      _passwordController.text,
    );

    setState(() {
      _isLoading = false;
