class SyncScreen extends StatefulWidget {
  final ApiClient apiClient;

  const SyncScreen({Key? key, required this.apiClient}) : super(key: key);

  @override
  State<SyncScreen> createState() => _SyncScreenState();
}

class _SyncScreenState extends State<SyncScreen> {
  bool _isLoading = false;
  String _message = '';
  DateTime? _lastSyncTime;
  final List<Map<String, dynamic>> _localData = [];

  Future<void> _performSync() async {
    setState(() {
      _isLoading = true;
      _message = '';
    });

    final dataToSync = {
      'timestamp': DateTime.now().toIso8601String(),
      'items': _localData,
    };

    final result = await widget.apiClient.syncData(dataToSync);

    setState(() {
      _isLoading = false;
    });

    if (result['success']) {
      setState(() {
        _message = 'Data synchronized successfully';
        _lastSyncTime = DateTime.now();
      });
    } else {
      setState(() {
        _message = result['error'] ?? 'Sync failed';
      });
    }
  }

  void _addLocalData() {
    setState(() {
      _localData.add({
        'id': DateTime.now().millisecondsSinceEpoch,
        'content': 'Item ${_localData.length + 1}',
        'timestamp': DateTime.now().toIso8601String(),
      });
    });
  }

  @override
  Widget build(BuildContext context) {
    return Padding(
      padding: const EdgeInsets.all(16.0),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          Card(
            child: Padding(
              padding: const EdgeInsets.all(16.0),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  const Text(
                    'Data Synchronization',
                    style: TextStyle(
                      fontSize: 20,
                      fontWeight: FontWeight.bold,
                    ),
                  ),
                  const SizedBox(height: 16),
                  if (_lastSyncTime != null)
                    Text(
                      'Last sync: ${_lastSyncTime!.toLocal()}',
                      style: TextStyle(color: Colors.grey[600]),
                    ),
                  const SizedBox(height: 16),
                  if (_isLoading)
                    const Center(child: CircularProgressIndicator())
                  else
                    ElevatedButton.icon(
                      onPressed: _performSync,
                      icon: const Icon(Icons.sync),
                      label: const Text('Sync Now'),
                    ),
                ],
              ),
            ),
          ),
          const SizedBox(height: 16),
          Card(
            child: Padding(
              padding: const EdgeInsets.all(16.0),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Row(
                    mainAxisAlignment: MainAxisAlignment.spaceBetween,
                    children: [
                      const Text(
                        'Local Data',
                        style: TextStyle(
                          fontSize: 18,
                          fontWeight: FontWeight.bold,
                        ),
                      ),
                      IconButton(
                        icon: const Icon(Icons.add),
                        onPressed: _addLocalData,
                      ),
                    ],
                  ),
                  const SizedBox(height: 8),
                  Text('Items: ${_localData.length}'),
                ],
              ),
            ),
          ),
          if (_message.isNotEmpty)
            Padding(
              padding: const EdgeInsets.only(top: 16),
              child: Card(
                color: _message.contains('success')
                    ? Colors.green.shade50
                    : Colors.red.shade50,
                child: Padding(
                  padding: const EdgeInsets.all(16.0),
                  child: Text(
                    _message,
                    style: TextStyle(
                      color: _message.contains('success')
                          ? Colors.green.shade900
                          : Colors.red.shade900,
                    ),
                  ),
                ),
              ),
            ),
          const SizedBox(height: 16),
          Expanded(
            child: Card(
              child: _localData.isEmpty
                  ? const Center(
                      child: Text('No local data. Add items to sync.'),
                    )
                  : ListView.builder(
                      itemCount: _localData.length,
                      itemBuilder: (context, index) {
                        final item = _localData[index];
                        return ListTile(
                          title: Text(item['content'] ?? ''),
                          subtitle: Text(item['timestamp'] ?? ''),
                          trailing: IconButton(
                            icon: const Icon(Icons.delete),
                            onPressed: () {
                              setState(() {
                                _localData.removeAt(index);
                              });
                            },
                          ),
                        );
                      },
                    ),
            ),
          ),
        ],
      ),
    );
  }
}